Future<double> getTemperatureForCity(double latitude, double longitude) async {
  final url = 'https://api.open-meteo.com/v1/forecast?latitude=$latitude&longitude=$longitude&current_weather=true';
  try {
    final response = await http.get(Uri.parse(url));
    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return data['current_weather']['temperature'];
    } else {
      throw Exception('Erreur HTTP: ${response.statusCode}');
    }
  } catch (e) {
    rethrow; // ou retourner une valeur par défaut comme -999.0
  }
}
```

```dart
void createPost(String title, String body) async {
  final response = await http.post(
    Uri.parse('https://jsonplaceholder.typicode.com/posts'),
    headers: {'Content-Type': 'application/json'},
    body: jsonEncode({'title': title, 'body': body, 'userId': 1}),
  );
  if (response.statusCode == 201) {
    print('Succès !');
  } else {
    print('Erreur ${response.statusCode}: ${response.body}');
  }
}
```

